import json
# variables from storage: var_call_gvA0dDXiISwj1KmF4YF45OIg and var_call_6P12KviUOmPFKiWR9hnQxMWV
books = var_call_gvA0dDXiISwj1KmF4YF45OIg
reviews = var_call_6P12KviUOmPFKiWR9hnQxMWV
# build review map
rev_map = {}
for r in reviews:
    pid = r.get('purchase_id')
    try:
        avg = float(r.get('avg_rating'))
    except:
        avg = None
    try:
        cnt = int(r.get('review_count'))
    except:
        cnt = None
    rev_map[pid] = {'avg_rating': avg, 'review_count': cnt}
# match books to reviews by converting bookid_X -> purchaseid_X
matches = []
for b in books:
    book_id = b.get('book_id')
    title = b.get('title')
    pid = None
    if book_id:
        if book_id.startswith('bookid_'):
            pid = 'purchaseid_' + book_id.split('_',1)[1]
        else:
            pid = 'purchaseid_' + book_id
    if pid and pid in rev_map:
        entry = {'title': title, 'book_id': book_id, 'purchase_id': pid, 'avg_rating': rev_map[pid]['avg_rating'], 'review_count': rev_map[pid]['review_count']}
        matches.append(entry)
# sort by avg_rating desc then review_count desc
matches.sort(key=lambda x: ((-x['avg_rating']) if x['avg_rating'] is not None else 0, -(x['review_count'] or 0)))
# prepare JSON string
result_json = json.dumps(matches)
print("__RESULT__:")
print(result_json)

